+const DOCTOR_SERVER_HIGH_CPU_PERCENT: f32 = 85.0;
+const DOCTOR_RUNTIME_HTTP_TIMEOUT_SECS: u64 = 2;
+const DOCTOR_RUNTIME_JSONRPC_TIMEOUT_SECS: u64 = 3;
